  "inlineSchema": "// NHS Appointment Management System - Prisma Schema\n// PostgreSQL\n\ngenerator client {\n  provider      = \"prisma-client-js\"\n  // Outside node_modules/.pnpm so Windows can replace query_engine-*.dll without EPERM on rename\n  // (common when the repo lives on Desktop / OneDrive or AV locks nested paths).\n  output        = \"../src/generated/prisma-client\"\n  binaryTargets = [\"native\", \"rhel-openssl-3.0.x\"]\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// --- Auth / Users (staff and patients use same User model; role distinguishes)\nmodel User {\n  id                  String    @id @default(cuid())\n  email               String    @unique\n  passwordHash        String    @map(\"password_hash\")\n  name                String?\n  role                UserRole  @default(PATIENT)\n  nhsNumber           String?   @unique @map(\"nhs_number\") // For patients\n  dateOfBirth         DateTime? @map(\"date_of_birth\")\n  phone               String?\n  createdAt           DateTime  @default(now()) @map(\"created_at\")\n  updatedAt           DateTime  @updatedAt @map(\"updated_at\")\n  resetToken          String?   @map(\"reset_token\")\n  resetTokenExpiresAt DateTime? @map(\"reset_token_expires_at\")\n\n  patient      Patient?\n  practitioner Practitioner?\n}\n\nenum UserRole {\n  PATIENT\n  PRACTITIONER\n  ADMIN\n}\n\n// --- Patient (links to User for login; holds NHS-specific demographics)\nmodel Patient {\n  id            String   @id @default(cuid())\n  userId        String   @unique @map(\"user_id\")\n  user          User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  nhsNumber     String   @unique @map(\"nhs_number\")\n  dateOfBirth   DateTime @map(\"date_of_birth\")\n  addressLine1  String?  @map(\"address_line1\")\n  addressLine2  String?  @map(\"address_line2\")\n  postcode      String?\n  gpSurgeryName String?  @map(\"gp_surgery_name\")\n  gpSurgeryCode String?  @map(\"gp_surgery_code\")\n  createdAt     DateTime @default(now()) @map(\"created_at\")\n  updatedAt     DateTime @updatedAt @map(\"updated_at\")\n\n  appointments Appointment[]\n  locationId   String?       @map(\"location_id\")\n  location     Location?     @relation(fields: [locationId], references: [id])\n}\n\n// --- Practitioner (GP, nurse, etc.)\nmodel Practitioner {\n  id         String   @id @default(cuid())\n  userId     String   @unique @map(\"user_id\")\n  user       User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  title      String? // Dr, Nurse, etc.\n  gmcNumber  String?  @unique @map(\"gmc_number\")\n  speciality String?\n  createdAt  DateTime @default(now()) @map(\"created_at\")\n  updatedAt  DateTime @updatedAt @map(\"updated_at\")\n\n  slots                 Slot[]\n  appointments          Appointment[]\n  availabilityWindows   PractitionerAvailabilityWindow[]\n  practitionerLocations PractitionerLocation[]\n}\n\n// --- Location (surgery / clinic)\nmodel Location {\n  id        String   @id @default(cuid())\n  name      String\n  address   String?\n  postcode  String?\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  slots                 Slot[]\n  patients              Patient[]\n  availabilityWindows   PractitionerAvailabilityWindow[]\n  practitionerLocations PractitionerLocation[]\n}\n\n/// Practitioners who work at a given clinic (for directory / filtering).\nmodel PractitionerLocation {\n  id             String       @id @default(cuid())\n  practitionerId String       @map(\"practitioner_id\")\n  practitioner   Practitioner @relation(fields: [practitionerId], references: [id], onDelete: Cascade)\n  locationId     String       @map(\"location_id\")\n  location       Location     @relation(fields: [locationId], references: [id], onDelete: Cascade)\n  createdAt      DateTime     @default(now()) @map(\"created_at\")\n\n  @@unique([practitionerId, locationId])\n  @@index([locationId])\n}\n\n/// Weekly recurring availability template for a practitioner at a location.\n/// `dayOfWeek`: 1 = Monday … 7 = Sunday (ISO-style).\n/// `windowStartMin` / `windowEndMin`: minutes from midnight (e.g. 9:00 → 540).\nmodel PractitionerAvailabilityWindow {\n  id              String       @id @default(cuid())\n  practitionerId  String       @map(\"practitioner_id\")\n  practitioner    Practitioner @relation(fields: [practitionerId], references: [id], onDelete: Cascade)\n  locationId      String       @map(\"location_id\")\n  location        Location     @relation(fields: [locationId], references: [id], onDelete: Cascade)\n  dayOfWeek       Int          @map(\"day_of_week\")\n  windowStartMin  Int          @map(\"window_start_min\")\n  windowEndMin    Int          @map(\"window_end_min\")\n  slotDurationMin Int          @default(30) @map(\"slot_duration_min\")\n\n  @@index([practitionerId, locationId])\n}\n\n// --- Slot (available time window for a practitioner at a location)\nmodel Slot {\n  id             String       @id @default(cuid())\n  practitionerId String       @map(\"practitioner_id\")\n  practitioner   Practitioner @relation(fields: [practitionerId], references: [id], onDelete: Cascade)\n  locationId     String       @map(\"location_id\")\n  location       Location     @relation(fields: [locationId], references: [id], onDelete: Cascade)\n  startAt        DateTime     @map(\"start_at\")\n  endAt          DateTime     @map(\"end_at\")\n  createdAt      DateTime     @default(now()) @map(\"created_at\")\n  updatedAt      DateTime     @updatedAt @map(\"updated_at\")\n\n  appointment Appointment?\n\n  @@unique([practitionerId, locationId, startAt, endAt], map: \"Slot_practitioner_location_start_end_key\")\n}\n\n// --- Appointment (booked slot by a patient)\nmodel Appointment {\n  id        String            @id @default(cuid())\n  patientId String            @map(\"patient_id\")\n  patient   Patient           @relation(fields: [patientId], references: [id], onDelete: Cascade)\n  slotId    String            @unique @map(\"slot_id\")\n  slot      Slot              @relation(fields: [slotId], references: [id], onDelete: Cascade)\n  status    AppointmentStatus @default(SCHEDULED)\n  reason    String? // Reason for visit\n  notes     String? // Clinician notes (after appointment)\n  createdAt DateTime          @default(now()) @map(\"created_at\")\n  updatedAt DateTime          @updatedAt @map(\"updated_at\")\n\n  practitionerId String       @map(\"practitioner_id\")\n  practitioner   Practitioner @relation(fields: [practitionerId], references: [id], onDelete: Cascade)\n}\n\nenum AppointmentStatus {\n  SCHEDULED\n  COMPLETED\n  CANCELLED\n  NO_SHOW\n}\n",
